mod builder;
mod oci;

use anyhow::Result;
use clap::{Parser, Subcommand};
use std::path::PathBuf;

#[derive(Parser)]
#[command(name = "repro", about = "Reproducible container image builder")]
struct Cli {
    #[command(subcommand)]
    command: Commands,
}

#[derive(Subcommand)]
enum Commands {
    Build(BuildArgs),
    Analyze(AnalyzeArgs),
}

BuildArgs dispatches to builder::Builder::new(params)?.build()
AnalyzeArgs dispatches to oci::parse_tarball() and oci::verify_digest()

